import urllib.request, json, time

pairs = ['BTCUSDT', 'ETHUSDT', 'XRPUSDT', 'XAGUSDT']
results = {}

for pair in pairs:
    try:
        # klines 4H - get 20 candles for ATR
        url = f'https://fapi.asterdex.com/fapi/v1/klines?symbol={pair}&interval=4h&limit=20'
        with urllib.request.urlopen(url, timeout=10) as r:
            data = json.loads(r.read())
        results[pair] = {'klines': data}
    except Exception as e:
        results[pair] = {'error': str(e)}

# funding rates
for pair in pairs:
    try:
        url = f'https://fapi.asterdex.com/fapi/v1/premiumIndex?symbol={pair}'
        with urllib.request.urlopen(url, timeout=10) as r:
            data = json.loads(r.read())
        results[pair]['funding'] = data
    except Exception as e:
        results[pair]['funding_error'] = str(e)

# order book depth
for pair in pairs:
    try:
        url = f'https://fapi.asterdex.com/fapi/v1/depth?symbol={pair}&limit=20'
        with urllib.request.urlopen(url, timeout=10) as r:
            data = json.loads(r.read())
        results[pair]['depth'] = data
    except Exception as e:
        results[pair]['depth_error'] = str(e)

print(json.dumps(results, indent=2))
